  ('disabled-e0adf6cd-moex-00238', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-110-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '甲公寓大廈管理委員會成立後依法向主管機關備查，主管機關若部分同意 備查，部分不同意。下列敘述何者正確？', '["甲得對不同意備查部分，提起課予義務訴訟請求主管機關同意備查", "甲就不同意備查部分，不得提起撤銷訴訟", "甲應就同意與不同意備查部分，一併提起撤銷訴訟", "甲得對不同意備查部分，提起確認訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:16+00:00", "source_pdf_sha1": "2f314779229e", "answer_pdf_sha1": "2390de2c8cd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
